## 1. Auth: Add Login & Signup

### Create `lib/providers/auth_provider.dart`

```dart
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthProvider with ChangeNotifier {
  static const String _isLoggedInKey = 'is_logged_in';
  static const String _userEmailKey = 'user_email';
  static const String _userNameKey = 'user_name';

  bool _isLoggedIn = false;
  String? _userEmail;
  String? _userName;

  bool get isLoggedIn => _isLoggedIn;
  String? get userEmail => _userEmail;
  String? get userName => _userName;

  Future<void> loadAuthState() async {
    final prefs = await SharedPreferences.getInstance();
    _isLoggedIn = prefs.getBool(_isLoggedInKey) ?? false;
    _userEmail = prefs.getString(_userEmailKey);
    _userName = prefs.getString(_userNameKey);
    notifyListeners();
  }

  Future<bool> login(String email, String password) async {
    if (email.trim().isEmpty || password.isEmpty) return false;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isLoggedInKey, true);
    await prefs.setString(_userEmailKey, email.trim());
    _userName = prefs.getString(_userNameKey) ?? email.split('@')[0];
    _isLoggedIn = true;
    _userEmail = email.trim();
    notifyListeners();
    return true;
  }

  Future<bool> signup(String name, String email, String password, String confirmPassword) async {
    if (name.trim().isEmpty || email.trim().isEmpty || password.isEmpty) return false;
    if (password != confirmPassword) return false;
    if (password.length < 6) return false;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isLoggedInKey, true);
    await prefs.setString(_userEmailKey, email.trim());
    await prefs.setString(_userNameKey, name.trim());
    _isLoggedIn = true;
    _userEmail = email.trim();
    _userName = name.trim();
    notifyListeners();
    return true;
  }

  Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isLoggedInKey, false);
    await prefs.remove(_userEmailKey);
    await prefs.remove(_userNameKey);
    _isLoggedIn = false;
    _userEmail = null;
    _userName = null;
    notifyListeners();
  }
}
```

