## 4. Bill scanning: improve amount & date extraction

In `lib/screens/scan_bill_screen.dart`, replace `_parseBillText` with:

```dart
Map<String, dynamic> _parseBillText(String text) {
  String? amount;
  DateTime? date;
  String? merchant;

  // Amount patterns - broader coverage
  final amountPatterns = [
    RegExp(r'(?:total|grand\s*total|amount|balance|due|sum|amt|subtotal|bill\s*amount)[\s:]*[₹$€]\s*([\d,]+\.?\d*)', caseSensitive: false),
    RegExp(r'(?:total|grand\s*total|amount|balance|due)[\s:]*\s*([\d,]+\.?\d{2})', caseSensitive: false),
    RegExp(r'[₹$€]\s*([\d,]+\.?\d{2})'),
    RegExp(r'(?:Rs\.?|INR)\s*([\d,]+\.?\d*)', caseSensitive: false),
    RegExp(r'\b([\d,]+\.?\d{2})\s*(?:USD|EUR|GBP|INR)?\s*$', caseSensitive: false),
    RegExp(r'\b(\d{1,3}(?:,\d{3})*(?:\.\d{2})?)\b'),
  ];

  final List<double> foundAmounts = [];
  for (final p in amountPatterns) {
    for (final m in p.allMatches(text)) {
      final s = m.group(1)?.replaceAll(',', '');
      final val = double.tryParse(s ?? '');
      if (val != null && val > 0 && val < 10000000) foundAmounts.add(val);
    }
  }

  // Prefer largest reasonable amount (often total)
  if (foundAmounts.isNotEmpty) {
    foundAmounts.sort((a, b) => b.compareTo(a));
    amount = foundAmounts.first.toStringAsFixed(2).replaceAll(RegExp(r'\.?0+$'), '');
  }

  // Date patterns
  final datePatterns = [
    RegExp(r'(\d{1,2})[/\-\.](\d{1,2})[/\-\.](\d{2,4})'),
    RegExp(r'(\d{4})[/\-](\d{2})[/\-](\d{2})'),
    RegExp(r'(\d{1,2})\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*[\s,]+(\d{2,4})', caseSensitive: false),
  ];

  const months = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
  final now = DateTime.now();

  for (final p in datePatterns) {
    for (final m in p.allMatches(text)) {
      int? d, mo, y;
      if (m.group(4) != null) {
        y = int.tryParse(m.group(4)!);
        mo = int.tryParse(m.group(5)!);
        d = int.tryParse(m.group(6)!);
      } else if (m.group(2) != null && RegExp(r'[a-zA-Z]').hasMatch(m.group(2)!)) {
        d = int.tryParse(m.group(1)!);
        mo = months.indexOf(m.group(2)!.toLowerCase().substring(0, 3)) + 1;
        y = int.tryParse(m.group(3)!);
        if (y! < 100) y += 2000;
      } else {
        d = int.tryParse(m.group(1)!);
        mo = int.tryParse(m.group(2)!);
        y = int.tryParse(m.group(3)!);
        if (y != null && y < 100) y += 2000;
      }
      if (d != null && mo != null && y != null && mo >= 1 && mo <= 12 && d >= 1 && d <= 31) {
        try {
          final dt = DateTime(y, mo, d);
          if (dt.isBefore(now.add(const Duration(days: 1)))) {
            date = dt;
            break;
          }
        } catch (_) {}
      }
    }
    if (date != null) break;
  }
  date ??= now;

  final lines = text.split(RegExp(r'\r?\n')).map((e) => e.trim()).where((e) => e.length > 3 && !RegExp(r'^[\d\s\$₹€\.\,\-]+$').hasMatch(e)).toList();
  if (lines.isNotEmpty) merchant = lines.first;

  return {'amount': amount, 'date': date, 'merchant': merchant};
}
```

